options.customCss:
:root {
	/* Fonts: Swapped to something punchy and structural */
	--font-family: 'Space Grotesk', 'Helvetica Neue', sans-serif;
	--font-weight-normal: 500; /* Beefed up base weight for presence */
	--font-weight-bold: 700;

	/* Font Sizes: Scaled up slightly for a bolder layout */
	--font-size-body: 14px;
	--font-size-label: 14px;
	--font-size-test-notice: 12px;
	--font-size-input: 14px;
	--font-size-header: 24px;
	--font-size-paragraph: 14px;
	--font-size-link: 14px;
	--font-size-error: 12px;
	--font-size-html-h1: 32px;
	--font-size-html-h2: 24px;
	--font-size-html-h3: 18px;
	--font-size-html-h4: 16px;
	--font-size-html-h5: 14px;
	--font-size-html-h6: 12px;
	--font-size-subheader: 16px;

	/* Colors: High Contrast Monochrome with striking accents */
	--color-background: #e0e0e0;         /* Concrete Grey */
	--color-test-notice-text: #000000;
	--color-test-notice-bg: #ccff00;     /* Volt Green Accent */
	--color-test-notice-border: #000000;

	--color-card-bg: #ffffff;
	--color-card-border: #000000;        /* Thick black borders */
	--color-card-shadow: #000000;        /* Solid black for harsh shadows */

	--color-header: #000000;
	--color-header-subtext: #444444;
	--color-label: #000000;
	--color-html-text: #000000;

	--color-input-border: #000000;
	--color-input-text: #000000;
	--color-focus-border: #0000ff;       /* Pure Blue Focus */

	--color-link: #0000ff;
	--color-html-link: #0000ff;

	--color-submit-btn-bg: #0000ff;      /* Pure Blue Button */
	--color-submit-btn-text: #ffffff;

	--color-error: #ff0000;              /* Pure Red */
	--color-required: #ff0000;
	--color-clear-button-bg: #000000;

	/* Border Radii: Zeroed out for sharp, blocky edges */
	--border-radius-card: 0px;
	--card-border-radius: 0px;
	--border-radius-input: 0px;
	--border-radius-clear-btn: 0px;

	/* Spacing: Increased for breathing room against heavy borders */
	--padding-container-top: 32px;
	--padding-card: 32px;
	--card-padding: 32px;
	--padding-test-notice-vertical: 16px;
	--padding-test-notice-horizontal: 24px;
	--margin-bottom-card: 24px;
	--card-margin-bottom: 24px;
	--padding-form-input: 16px;

	/* Dimensions: Slightly chunkier */
	--container-width: 480px;
	--submit-btn-height: 54px;
	--checkbox-size: 20px;

	/* Others: The signature solid brutalist drop shadow */
	--box-shadow-card: 6px 6px 0px 0px var(--color-card-shadow);
	--opacity-placeholder: 1; /* Solid placeholders */
}

